import{_ as a,o as i,c as e,ai as o}from"./chunks/framework.DyvBZb4W.js";const s=JSON.parse('{"title":"更新记录","description":"","frontmatter":{},"headers":[],"relativePath":"mods/sts2-god-mod/changelog.md","filePath":"mods/sts2-god-mod/changelog.md","lastUpdated":1779029223000}'),d={name:"mods/sts2-god-mod/changelog.md"};function r(t,l,h,c,n,u){return i(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="更新记录" tabindex="-1">更新记录 <a class="header-anchor" href="#更新记录" aria-label="Permalink to &quot;更新记录&quot;">​</a></h1><p>这里整理 STS2 God Mod 面向玩家的更新说明。当前站点详情页显示版本为 <code>1.6.2</code>，以下已按 Mod 代码中的版本更新介绍整理到 <code>v1.6.2</code>。</p><p>下载最新版：<a href="https://pan.quark.cn/s/2c8c2850621d" target="_blank" rel="noreferrer">夸克下载</a></p><h2 id="v1-6-2" tabindex="-1">v1.6.2 <a class="header-anchor" href="#v1-6-2" aria-label="Permalink to &quot;v1.6.2&quot;">​</a></h2><ul><li>同版本多人联机下，God Mod 现在可以选择自己或队友作为操作对象。</li><li>支持对目标玩家编辑资源、卡牌、药水和遗物；也支持目标卡牌升级 / 删除、目标药水 / 遗物删除、预设药水 / 预设遗物添加。</li><li>单机、混装模式、或尚未确认全员同版本时，操作对象选择器会隐藏，避免误用。</li><li>战斗快捷区域更紧凑，更方便快速查看和操作。</li></ul><h2 id="v1-6-1" tabindex="-1">v1.6.1 <a class="header-anchor" href="#v1-6-1" aria-label="Permalink to &quot;v1.6.1&quot;">​</a></h2><ul><li>正式版兼容性修复。</li></ul><h2 id="v1-6-0" tabindex="-1">v1.6.0 <a class="header-anchor" href="#v1-6-0" aria-label="Permalink to &quot;v1.6.0&quot;">​</a></h2><ul><li>战斗胜利后的卡牌奖励可自定义候选数量；</li><li>战斗遗物奖励可改为多候选里 N 选 1。</li><li>资源编辑区更紧凑：常用资源字段、奖励数量、火堆辅助和先民相关设置分组更省空间。</li><li>修复先民链式奖励领取后，奖励界面偶发无法正确收尾的问题。</li><li>修复无法隐藏 G 面板问题</li><li>提供种子、随机数管理功能（beta）：包含卡牌预览、后续事件预览等</li></ul><h2 id="v1-5-6" tabindex="-1">v1.5.6 <a class="header-anchor" href="#v1-5-6" aria-label="Permalink to &quot;v1.5.6&quot;">​</a></h2><ul><li>列表编辑更快：现在可以双击当前卡牌进行升级，三连击当前卡牌、遗物或药水进行删除，也可以三连击待选列表项目快速添加。</li><li>修复正式版游戏中开启先民遗物刷新后，涅奥房间可能黑屏的问题。</li><li>优化 beta 版下涅奥房间、先古房间和 <code>G</code> 面板相关兼容性。</li><li>战斗快捷项新增格挡 <code>+10</code>；资源编辑新增当前格挡值，可直接设置本场战斗中的格挡。</li><li>现在可以将手牌上限提高到 10 以上。</li><li>资源输入框和按钮更紧凑，宽窗口支持两列显示，窄窗口自动切回一列。</li></ul><h2 id="v1-5-5" tabindex="-1">v1.5.5 <a class="header-anchor" href="#v1-5-5" aria-label="Permalink to &quot;v1.5.5&quot;">​</a></h2><ul><li>Beta 版本中 <code>G</code> 面板可以正常打开。</li><li>刷新或增加先民选项时，会避开不该同时出现的遗物组合。</li><li>修复开局先民房间可能卡住、不出现下一步选项的问题。</li></ul><h2 id="v1-5-4" tabindex="-1">v1.5.4 <a class="header-anchor" href="#v1-5-4" aria-label="Permalink to &quot;v1.5.4&quot;">​</a></h2><ul><li>为混装联机提供新的专家模式：确实需要时，可以临时放开 God Mod 对混装联机的安全限制，用于更高风险的测试或设置调整。</li><li>为降低误开导致的不同步风险，专家模式会在每次进入新的一局后自动重置为关闭。</li></ul><h2 id="v1-5-3" tabindex="-1">v1.5.3 <a class="header-anchor" href="#v1-5-3" aria-label="Permalink to &quot;v1.5.3&quot;">​</a></h2><ul><li>悬浮 <code>G</code> 按钮恢复更稳。</li><li>修复了在同时使用贴边吸附、极低透明度或显示开关后，重启游戏时悬浮 <code>G</code> 按钮可能消失的问题。</li></ul><h2 id="v1-5-2" tabindex="-1">v1.5.2 <a class="header-anchor" href="#v1-5-2" aria-label="Permalink to &quot;v1.5.2&quot;">​</a></h2><ul><li>修复了首次开局选完角色后尝试获取遗物信息失败，导致黑屏的问题。</li><li>先民事件识别更稳，减少了新版先民事件漏判导致的异常。</li></ul><h2 id="v1-5-1" tabindex="-1">v1.5.1 <a class="header-anchor" href="#v1-5-1" aria-label="Permalink to &quot;v1.5.1&quot;">​</a></h2><ul><li>混装模式下，非战斗时的牌库管理更灵活。</li><li>战斗中为了更安全地同步，混装兼容模式仍然只允许操作手牌。</li><li>离开战斗后，牌堆选择可以切回牌库，方便查看和整理牌库卡牌。</li></ul><h2 id="v1-5-0" tabindex="-1">v1.5.0 <a class="header-anchor" href="#v1-5-0" aria-label="Permalink to &quot;v1.5.0&quot;">​</a></h2><ul><li>新增 6 种界面语言支持：繁體中文、日本語、한국어、Русский、Español 和 Português do Brasil。</li><li>混装联机兼容模式下，新增更多战斗快捷支持：能量 +5、辉星 +5、抽牌、回满血，以及秒杀全部敌人。</li><li>混装兼容模式开启时，卡牌管理只允许操作手牌，牌堆选择也会强制锁定为手牌。</li><li>支持添加手牌、删除手牌、升级手牌，以及对手牌附魔。</li></ul><h2 id="v1-4-3" tabindex="-1">v1.4.3 <a class="header-anchor" href="#v1-4-3" aria-label="Permalink to &quot;v1.4.3&quot;">​</a></h2><ul><li>混装联机更稳定。</li><li>当房间内玩家使用的 God Mod 版本不完全一致时，联机兼容提示更清晰，混装联机流程也更稳定、更安全。</li></ul><h2 id="v1-4-2" tabindex="-1">v1.4.2 <a class="header-anchor" href="#v1-4-2" aria-label="Permalink to &quot;v1.4.2&quot;">​</a></h2><ul><li>在“其他设置”和 Mod Config 中新增重置入口，可将本地 God Mod 设置恢复为默认值。</li><li>重置前会有二次确认，用于防止误删本地设置和自定义预设。</li><li>可以在“其他设置”中自定义面板开关快捷键和重启房间快捷键，并分别调整长按触发时长。</li><li>为避免冲突，这两个长按功能需要使用不同的按键。</li></ul><h2 id="v1-4-1" tabindex="-1">v1.4.1 <a class="header-anchor" href="#v1-4-1" aria-label="Permalink to &quot;v1.4.1&quot;">​</a></h2><ul><li>修复联机下火堆额外删牌的接入方式，改为通过原生休息站选项列表生成，按正确的拥有者玩家执行，并且删牌后不再错误占用整个休息站回合。</li><li>补上图标与本地化缺失导致的后续问题，避免休息站同步链路被异常打断、删牌按钮状态不更新，或离开火堆后进一步触发联机不同步。</li><li>G 面板里常用的数值输入框，例如抽牌数量和敌人血量，现在会记住你上次在本地填过的值，不再每次都重置成 1。</li></ul><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0&quot;">​</a></h2><ul><li>多人安全：绝大多数会改动卡牌、卡组、遗物、药水、资源、战斗状态、敌人和力量的编辑工具，现在都会走同步多人 action，不再只改本地客户端。</li><li>联机兼容性：在“其他设置”中新增“放宽联机大厅检查”开关。默认保持为更安全的 gameplay-affecting 模式。把它关掉后，房主和客户端混装时可能更容易进房，但使用会改本局或战斗状态的功能仍可能导致联机不同步、断线甚至崩溃。</li><li>长按 <code>R</code> 重启房间：在“其他设置”中新增长按 <code>R</code> 键 0.3 秒重启当前房间的开关，默认开启，且不会额外显示按钮。</li><li>稳定性与排查：提升事件房中长按 <code>R</code> 重启房间的稳定性，补强无限预设恢复时的容错逻辑，并优化日志输出，方便继续排查多人局中的问题。</li></ul><h2 id="v1-3-3" tabindex="-1">v1.3.3 <a class="header-anchor" href="#v1-3-3" aria-label="Permalink to &quot;v1.3.3&quot;">​</a></h2><ul><li>移动端兼容性热修复。</li></ul><h2 id="v1-3-2" tabindex="-1">v1.3.2 <a class="header-anchor" href="#v1-3-2" aria-label="Permalink to &quot;v1.3.2&quot;">​</a></h2><ul><li>增加悬浮 <code>G</code> 按钮的显示开关、大小和透明度自定义，并接入持久化与运行时同步。</li><li>修复建筑师这类事件内嵌战斗场景出现两个 <code>G</code> 按钮的问题。</li><li>战斗快捷新增能量 <code>+5</code> 和辉星 <code>+5</code>。</li><li>新增 Traveler 模式。</li><li>“按职业添加卡牌”的职业筛选改成动态读取实际角色卡池，所以 Mod 自定义角色的卡牌也能按职业列出来。</li><li><code>AddCard(...)</code> 在真多人模式下改成走自定义同步 action，不再直接本地裸改。</li><li>事件目录补进了 <code>shared ancient</code>，所以像 <code>Darv</code> 这类共享先民事件也能出现在列表里。</li><li>修复遗物 / 药水预设“另存为新预设”后重启丢失的问题。</li><li>遗物、药水、卡组自定义预设在“保存为新预设”时，遇到重名现在会自动补 <code>-1</code>、<code>-2</code> 后缀。</li></ul><h2 id="v1-3-1" tabindex="-1">v1.3.1 <a class="header-anchor" href="#v1-3-1" aria-label="Permalink to &quot;v1.3.1&quot;">​</a></h2><ul><li>修复部分设备上火堆选项无法点击、必须跳转事件后才能继续的问题。</li><li>修复先民事件中可能卡住、无法正常继续流程的问题。</li><li>优化 Mod Config 打开时的刷新逻辑，减少重复重建 UI 带来的卡顿。</li></ul><h2 id="v1-3-0" tabindex="-1">v1.3.0 <a class="header-anchor" href="#v1-3-0" aria-label="Permalink to &quot;v1.3.0&quot;">​</a></h2><ul><li>新增位于 Mod Config 中的 God Mod 配置页，可在设置页里直接关闭高风险功能。</li><li>God Mod 配置与局内 G 面板中的相关开关现已保持同步。</li><li>优化遗物预设编辑。</li></ul><h2 id="v1-2-1" tabindex="-1">v1.2.1 <a class="header-anchor" href="#v1-2-1" aria-label="Permalink to &quot;v1.2.1&quot;">​</a></h2><ul><li>全新安装时，<code>先民刷新</code> 与 <code>先民展示改写</code> 现在默认关闭，避免初次使用时对原版流程造成干扰。</li><li>修复先民房间中刷新按钮的显示问题：在做出选择后，或离开房间后，按钮会正确隐藏。</li><li>继续优化设置项与悬浮 <code>G</code> 按钮的视觉表现和交互体验，让控件更清晰、更易点按。</li></ul><h2 id="v1-2-0" tabindex="-1">v1.2.0 <a class="header-anchor" href="#v1-2-0" aria-label="Permalink to &quot;v1.2.0&quot;">​</a></h2><ul><li>新增 Mod 语言切换：跟随游戏、英文、简体中文。</li><li>新增遗物预设与药水预设：支持保存、覆盖、删除、一键应用默认 / 自定义预设。</li><li>多个目录支持“最近使用优先”排序：卡牌、遗物、药水、状态、事件、敌人。</li><li>卡牌 / 状态 / 事件相关面板体验增强：添加卡牌支持“直接升级”、卡牌目录新增独立预览、状态区新增预览面板。</li><li>药水管理增强：支持删除选中药水，可把当前药水装载到预设编辑器。</li><li>浮动 <code>G</code> 按钮和主面板交互继续优化：面板更大、拖拽区域更稳定、关闭按钮补了点击音效、按钮位置恢复逻辑更稳。</li><li>日志与排障信息增强：启动时记录游戏版本和已启用 Mod 列表，复制日志时附带 Mod / game 版本、语言、平台与已启用 Mod，日志噪音进一步收敛。</li><li>先民事件刷新相关逻辑和日志又做了一轮整理。</li><li>修复：移除了不必要的临时调试文件输出。</li></ul><h2 id="v1-1-0" tabindex="-1">v1.1.0 <a class="header-anchor" href="#v1-1-0" aria-label="Permalink to &quot;v1.1.0&quot;">​</a></h2><ul><li>新增“解锁全部”功能。</li><li>新增“允许先民 SL”功能。</li><li>修复部分在手机端失效的功能：如先民刷新、火堆删牌、设置最大生命值。</li><li>支持查看并复制 Mod 报错日志，排查问题更方便。</li></ul><h2 id="v1-0-1" tabindex="-1">v1.0.1 <a class="header-anchor" href="#v1-0-1" aria-label="Permalink to &quot;v1.0.1&quot;">​</a></h2><ul><li>修复移动终端中的模组兼容性问题。</li></ul><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0&quot;">​</a></h2><ul><li>全面重做 God Mode 面板交互，分组更清晰，内容区更大，常用功能更集中。</li><li>卡牌编辑大幅增强，支持勾选多张卡牌、批量升级 / 降级、同名牌一键升级、整套牌一键升级 / 降级。</li><li>卡牌附魔不再只能新增，现在可以直接修改和覆盖已有附魔。</li><li>卡牌筛选能力增强，加入全部职业、当前职业、各职业、无色牌等分类，找牌更方便。</li><li>卡组预设从卡牌编辑中独立出来，作为单独分组管理，结构更清爽。</li><li>遗物编辑支持勾选多个目标，进行批量添加和批量删除。</li><li>新增卡牌附加效果相关能力，并补了对应的运行时 Patch，让特殊效果能真正生效。</li><li>悬浮 <code>G</code> 按钮支持自由拖动，只有贴边时才会自动吸附隐藏，并且会记住位置。</li><li>新增“关于 / 说明”分组，补充使用提示。</li><li>敌人预览、卡牌预览、拖拽移动人物等体验也做了持续优化。</li></ul><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><ul><li>功能增强。</li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><ul><li>首次发布。</li></ul>',53)])])}const b=a(d,[["render",r]]);export{s as __pageData,b as default};
